const request = $input.first().json || {};
const headers = request.headers || {};
const incomingKey = String(headers['x-crm-key'] || headers['X-Crm-Key'] || headers['X-CRM-KEY'] || '').trim();
const expectedKey = String($env.CRM_API_KEY || '').trim();
if (!expectedKey || incomingKey !== expectedKey) {
  return [{ json: { success: false, ok: false, shouldContinue: false, httpStatus: 401, error: { code: 'UNAUTHORIZED', message: 'unauthorized' } } }];
}
const body = request.body && typeof request.body === 'object' ? request.body : request;
const invoiceId = Math.trunc(Number(body.invoiceId || 0));
const mode = String(body.mode || 'test').trim().toLowerCase() === 'production' ? 'production' : 'test';
const idempotencyKey = String(body.idempotencyKey || '').trim();
const requestId = String(body.requestId || '').trim() || `barobill-${Date.now()}`;
if (!invoiceId || !idempotencyKey) {
  return [{ json: { success: false, ok: false, shouldContinue: false, httpStatus: 400, requestId, invoiceId, idempotencyKey, error: { code: 'INVALID_REQUEST', message: 'invoiceId와 idempotencyKey가 필요합니다.' } } }];
}
return [{ json: { success: true, ok: true, shouldContinue: true, httpStatus: 200, requestId, invoiceId, idempotencyKey, mode, body } }];

const source = $('발급 요청 검증').item.json;
const body = source.body || {};
const invoiceResponse = $('CRM 명세표 fresh read').item.json || {};
const itemsResponse = $('CRM 품목 fresh read').item.json || {};
const customerResponse = $('CRM 고객 fresh read').item.json || {};
const settingsResponse = $('CRM 회사 설정 fresh read').item.json || {};

function unwrapProxyBody(response) {
  if (response && typeof response === 'object' && response.body && typeof response.body === 'object') return response.body;
  return response || {};
}
function unwrapProxyData(response) {
  const body = unwrapProxyBody(response);
  return body && typeof body === 'object' && Object.prototype.hasOwnProperty.call(body, 'data') ? body.data : body;
}
function unwrapProxyList(response) {
  const data = unwrapProxyData(response);
  if (data && Array.isArray(data.list)) return data.list;
  if (Array.isArray(data)) return data;
  return [];
}

let invoice = unwrapProxyData(invoiceResponse);
let itemList = unwrapProxyList(itemsResponse);
let customer = unwrapProxyData(customerResponse) || {};
let settingsList = unwrapProxyList(settingsResponse);
let settings = settingsList[0] || unwrapProxyData(settingsResponse) || {};

function hasCrmRecord(record) {
  return record && typeof record === 'object' && Number(record.Id || record.id || 0) > 0;
}
function hasSettingRecord(record) {
  return record && typeof record === 'object' && Object.keys(record).some((key) => !['success', 'ok', 'timestamp'].includes(key));
}
async function crmProxyRequest(payload) {
  const url = String($env.CRM_PROXY_URL || 'https://n8n.pressco21.com/webhook/crm-proxy').trim();
  const key = String($env.CRM_API_KEY || '').trim();
  if (!url || !key) return {};
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: { 'Content-Type': 'application/json', 'x-crm-key': key },
      body: payload,
      json: true,
      timeout: 20000,
    });
    return unwrapProxyBody(response);
  } catch (error) {
    return { success: false, error: { code: 'CRM_PROXY_FALLBACK_FAILED', message: error.message } };
  }
}

// 일부 n8n HTTP Request 실행에서 프록시 응답 대신 Node.js response 객체가 전달되는 경우가 있어
// 발급 직전 Code 노드에서 같은 CRM proxy를 한 번 더 안전하게 조회한다.
if (!hasCrmRecord(invoice)) {
  const fallback = await crmProxyRequest({ table: 'invoices', method: 'GET', recordId: source.invoiceId });
  invoice = unwrapProxyData(fallback);
}
if (!Array.isArray(itemList) || itemList.length === 0) {
  const fallback = await crmProxyRequest({ table: 'items', method: 'GET', params: { where: `(invoice_id,eq,${source.invoiceId})`, limit: 200, sort: 'Id' } });
  itemList = unwrapProxyList(fallback);
}
if (!hasCrmRecord(customer)) {
  const customerId = Number(invoice?.customer_id || invoice?.customerId || body.customerId || 0);
  if (customerId > 0) {
    const fallback = await crmProxyRequest({ table: 'customers', method: 'GET', recordId: customerId });
    customer = unwrapProxyData(fallback) || {};
  }
}
if (!hasSettingRecord(settings) || (!settings.bizno && !settings.company)) {
  const fallback = await crmProxyRequest({ table: 'settings', method: 'GET', params: { limit: 1 } });
  const fallbackList = unwrapProxyList(fallback);
  settings = fallbackList[0] || unwrapProxyData(fallback) || settings || {};
}

const staticData = $getWorkflowStaticData('global');
staticData.barobillTaxInvoiceRequestLog = staticData.barobillTaxInvoiceRequestLog || {};
staticData.barobillTaxInvoiceMgtLog = staticData.barobillTaxInvoiceMgtLog || {};
const requestLog = staticData.barobillTaxInvoiceRequestLog;
const mgtLog = staticData.barobillTaxInvoiceMgtLog;
const now = new Date().toISOString();
const prefix = '[ACCOUNTING_INVOICE_META]';

function parseInteger(value) {
  if (typeof value === 'number') return Number.isFinite(value) ? Math.trunc(value) : 0;
  const parsed = Number(String(value ?? '').replace(/,/g, '').replace(/원/g, '').trim());
  return Number.isFinite(parsed) ? Math.trunc(parsed) : 0;
}
function normalizeText(value) { return String(value ?? '').trim(); }
function digitsOnly(value) { return normalizeText(value).replace(/\D/g, ''); }
function normalizeDate(value) {
  const raw = normalizeText(value);
  const digits = raw.replace(/\D/g, '');
  if (digits.length >= 8) return digits.slice(0, 8);
  const d = new Date();
  const kst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
  return `${kst.getUTCFullYear()}${String(kst.getUTCMonth() + 1).padStart(2, '0')}${String(kst.getUTCDate()).padStart(2, '0')}`;
}
function xmlEscape(value) {
  return normalizeText(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}
function fnv1a(value) {
  let h = 0x811c9dc5;
  const text = String(value);
  for (let i = 0; i < text.length; i += 1) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}
function parseMeta(memo) {
  const line = normalizeText(memo).split('\n').map((entry) => entry.trim()).find((entry) => entry.startsWith(prefix));
  if (!line) return {};
  try { return JSON.parse(line.slice(prefix.length).trim()) || {}; } catch (error) { return {}; }
}
function serializeMeta(memo, nextMeta) {
  const visible = normalizeText(memo).replace(/\r\n/g, '\n').split('\n').filter((line) => line.trim() && !line.trim().startsWith(prefix));
  return [...visible, `${prefix} ${JSON.stringify(nextMeta)}`].join('\n').trim();
}
function fail(httpStatus, code, message, extra = {}) {
  return [{ json: { success: false, ok: false, shouldCallProvider: false, httpStatus, requestId: source.requestId, invoiceId: source.invoiceId, idempotencyKey: source.idempotencyKey, provider: 'barobill', mode: source.mode, error: { code, message }, ...extra } }];
}
function coalesce(...values) {
  for (const value of values) {
    const text = normalizeText(value);
    if (text) return text;
  }
  return '';
}
function makeProviderMgtKey(invoiceId, invoiceNo, idempotencyKey) {
  const idPart = String(invoiceId).replace(/\D/g, '').slice(-7) || '0';
  const noPart = normalizeText(invoiceNo).replace(/[^0-9A-Za-z]/g, '').slice(-6) || 'INV';
  const hash = fnv1a(idempotencyKey).slice(0, 8).toUpperCase();
  return `PC${idPart}-${noPart}-${hash}`.slice(0, 24);
}
function isTaxableLine(item) {
  const raw = normalizeText(item.taxable ?? item.taxable_yn ?? item.tax_type).toLowerCase();
  return !['n', 'no', 'false', '0', '면세', '비과세'].includes(raw);
}
function splitVatIncludedTotal(total, taxable = true) {
  const normalizedTotal = Math.max(0, parseInteger(total));
  if (!taxable || normalizedTotal <= 0) return { supply: normalizedTotal, tax: 0, total: normalizedTotal };
  const tax = Math.round(normalizedTotal / 11);
  return { supply: normalizedTotal - tax, tax, total: normalizedTotal };
}
function vatIncludedLineTotal(item) {
  const quantity = Math.max(1, parseInteger(item.quantity));
  const unitPrice = parseInteger(item.unit_price ?? item.unitPrice);
  if (unitPrice > 0) return Math.max(0, quantity * unitPrice);
  const explicitTotal = parseInteger(item.total_amount ?? item.totalAmount);
  if (explicitTotal > 0) return explicitTotal;
  const supply = parseInteger(item.supply_amount ?? item.supplyAmount);
  const tax = parseInteger(item.tax_amount ?? item.taxAmount);
  return Math.max(0, supply + tax);
}
function lineAmount(item) {
  return splitVatIncludedTotal(vatIncludedLineTotal(item), isTaxableLine(item));
}
function buildItemRows(items, writeDate) {
  return items.map((item) => {
    const amount = lineAmount(item);
    const quantity = Math.max(1, parseInteger(item.quantity));
    const unitPrice = quantity > 0 ? Math.round(amount.supply / quantity) : amount.supply;
    return {
      purchaseExpiry: writeDate,
      name: coalesce(item.product_name, item.name, item.itemName, '품목'),
      information: coalesce(item.unit, item.spec, item.information),
      chargeableUnit: String(quantity),
      unitPrice: String(unitPrice),
      amount: String(amount.supply),
      tax: String(amount.tax),
      description: coalesce(item.description, item.memo),
      _amount: amount,
    };
  });
}
function buildPartyXml(name, party) {
  return [
    `<${name}>`,
    `<ContactID>${xmlEscape(party.contactId || '')}</ContactID>`,
    `<CorpNum>${xmlEscape(party.corpNum || '')}</CorpNum>`,
    `<MgtNum>${xmlEscape(party.mgtNum || '')}</MgtNum>`,
    `<CorpName>${xmlEscape(party.corpName || '')}</CorpName>`,
    `<TaxRegID>${xmlEscape(party.taxRegId || '')}</TaxRegID>`,
    `<CEOName>${xmlEscape(party.ceoName || '')}</CEOName>`,
    `<Addr>${xmlEscape(party.addr || '')}</Addr>`,
    `<BizClass>${xmlEscape(party.bizClass || '')}</BizClass>`,
    `<BizType>${xmlEscape(party.bizType || '')}</BizType>`,
    `<ContactName>${xmlEscape(party.contactName || '')}</ContactName>`,
    `<TEL>${xmlEscape(party.tel || '')}</TEL>`,
    `<HP>${xmlEscape(party.hp || '')}</HP>`,
    `<Email>${xmlEscape(party.email || '')}</Email>`,
    `</${name}>`,
  ].join('');
}
function buildIssueSoapTemplate({ corpNum, providerMgtKey, supplier, buyer, writeDate, amounts, itemRows, sendSms, mailTitle, sendEmail, purposeType }) {
  const itemXml = itemRows.map((item) => [
    '<TaxInvoiceTradeLineItem>',
    `<PurchaseExpiry>${xmlEscape(item.purchaseExpiry)}</PurchaseExpiry>`,
    `<Name>${xmlEscape(item.name)}</Name>`,
    `<Information>${xmlEscape(item.information)}</Information>`,
    `<ChargeableUnit>${xmlEscape(item.chargeableUnit)}</ChargeableUnit>`,
    `<UnitPrice>${xmlEscape(item.unitPrice)}</UnitPrice>`,
    `<Amount>${xmlEscape(item.amount)}</Amount>`,
    `<Tax>${xmlEscape(item.tax)}</Tax>`,
    `<Description>${xmlEscape(item.description)}</Description>`,
    '</TaxInvoiceTradeLineItem>',
  ].join('')).join('');
  const invoicer = { ...supplier, mgtNum: providerMgtKey };
  const invoicee = { ...buyer, mgtNum: '' };
  return `<?xml version="1.0" encoding="utf-8"?>` +
    `<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">` +
    `<soap:Body>` +
    `<RegistAndIssueTaxInvoice xmlns="http://ws.baroservice.com/">` +
    `<CERTKEY>__BAROBILL_CERTKEY__</CERTKEY>` +
    `<CorpNum>${xmlEscape(corpNum)}</CorpNum>` +
    `<Invoice>` +
    `<InvoiceKey></InvoiceKey>` +
    buildPartyXml('InvoicerParty', invoicer) +
    buildPartyXml('InvoiceeParty', invoicee) +
    buildPartyXml('BrokerParty', {}) +
    `<InvoiceeASPEmail>${sendEmail ? xmlEscape(buyer.email || '') : ''}</InvoiceeASPEmail>` +
    `<IssueDirection>1</IssueDirection>` +
    `<TaxInvoiceType>1</TaxInvoiceType>` +
    `<TaxType>1</TaxType>` +
    `<TaxCalcType>1</TaxCalcType>` +
    `<PurposeType>${xmlEscape(purposeType || '2')}</PurposeType>` +
    `<ModifyCode></ModifyCode><Kwon></Kwon><Ho></Ho><SerialNum></SerialNum>` +
    `<Cash></Cash><ChkBill></ChkBill><Note></Note><Credit></Credit>` +
    `<WriteDate>${xmlEscape(writeDate)}</WriteDate>` +
    `<AmountTotal>${xmlEscape(String(amounts.supplyAmount))}</AmountTotal>` +
    `<TaxTotal>${xmlEscape(String(amounts.taxAmount))}</TaxTotal>` +
    `<TotalAmount>${xmlEscape(String(amounts.totalAmount))}</TotalAmount>` +
    `<Remark1>${xmlEscape(body.invoiceNo || invoice.invoice_no || '')}</Remark1>` +
    `<Remark2>${xmlEscape(source.idempotencyKey)}</Remark2>` +
    `<Remark3>PRESSCO21 CRM</Remark3>` +
    `<TaxInvoiceTradeLineItems>${itemXml}</TaxInvoiceTradeLineItems>` +
    `</Invoice>` +
    `<SendSMS>${sendSms ? 'true' : 'false'}</SendSMS>` +
    `<ForceIssue>false</ForceIssue>` +
    `<MailTitle>${xmlEscape(mailTitle || '프레스코21 전자세금계산서')}</MailTitle>` +
    `</RegistAndIssueTaxInvoice>` +
    `</soap:Body></soap:Envelope>`;
}
function buildMgtCheckSoapTemplate(corpNum, providerMgtKey) {
  return `<?xml version="1.0" encoding="utf-8"?>` +
    `<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">` +
    `<soap:Body><CheckMgtNumIsExists xmlns="http://ws.baroservice.com/">` +
    `<CERTKEY>__BAROBILL_CERTKEY__</CERTKEY>` +
    `<CorpNum>${xmlEscape(corpNum)}</CorpNum>` +
    `<MgtKey>${xmlEscape(providerMgtKey)}</MgtKey>` +
    `</CheckMgtNumIsExists></soap:Body></soap:Envelope>`;
}

if (source.mode === 'production' && String($env.BAROBILL_ALLOW_PRODUCTION || '').trim() !== 'true') {
  return fail(403, 'PRODUCTION_DISABLED', '운영 발급은 BAROBILL_ALLOW_PRODUCTION=true와 별도 승인 전까지 차단됩니다.');
}
if (!String($env.BAROBILL_CERTKEY || '').trim()) {
  return fail(500, 'BAROBILL_CERTKEY_MISSING', 'BAROBILL_CERTKEY runtime 환경변수가 설정되지 않았습니다.');
}
if (!invoice || !Number(invoice.Id || invoice.id)) return fail(404, 'INVOICE_NOT_FOUND', 'CRM에서 명세표를 찾지 못했습니다.');

const invoiceId = Math.trunc(Number(invoice.Id || invoice.id));
const invoiceNo = coalesce(invoice.invoice_no, body.invoiceNo);
if (invoiceId !== source.invoiceId) return fail(409, 'INVOICE_MISMATCH', 'CRM fresh read 명세표 ID가 요청과 다릅니다.');
if (!invoiceNo) return fail(400, 'INVOICE_NO_REQUIRED', '명세표 번호가 필요합니다.');

const meta = parseMeta(invoice.memo);
const taxInvoiceMeta = meta.taxInvoice && typeof meta.taxInvoice === 'object' ? meta.taxInvoice : {};
const blockedStatuses = new Set(['requesting', 'requested', 'issued']);
if (blockedStatuses.has(String(meta.taxInvoiceStatus || taxInvoiceMeta.status || '').trim())) {
  return fail(200, 'DUPLICATE_CRM_META', '이미 세금계산서 발급 요청 또는 발급이 기록된 명세표입니다.', {
    duplicate: true,
    providerMgtKey: taxInvoiceMeta.mgtKey || taxInvoiceMeta.providerMgtKey || '',
    status: meta.taxInvoiceStatus || taxInvoiceMeta.status,
  });
}

const existingLog = requestLog[source.idempotencyKey];
if (existingLog && ['requesting', 'requested', 'issued', 'provider_existing'].includes(String(existingLog.status || ''))) {
  return fail(200, 'DUPLICATE_IDEMPOTENCY_KEY', '같은 idempotencyKey 발급 요청 이력이 있어 신규 SOAP 발급을 차단했습니다.', {
    duplicate: true,
    providerMgtKey: existingLog.provider_mgt_key,
    status: existingLog.status,
    existingRequest: {
      requestId: existingLog.request_id,
      createdAt: existingLog.created_at,
      updatedAt: existingLog.updated_at,
    },
  });
}

const itemRows = buildItemRows(itemList, normalizeDate(invoice.invoice_date || body.writeDate));
if (itemRows.length === 0) return fail(400, 'ITEMS_REQUIRED', '세금계산서 품목이 1개 이상 필요합니다.');
const itemSupplyTotal = itemRows.reduce((sum, item) => sum + item._amount.supply, 0);
const itemTaxTotal = itemRows.reduce((sum, item) => sum + item._amount.tax, 0);
const itemTotal = itemRows.reduce((sum, item) => sum + item._amount.total, 0);
const fallbackInvoiceTotal = parseInteger(invoice.total_amount ?? body.amounts?.totalAmount);
const fallbackInvoiceAmount = splitVatIncludedTotal(fallbackInvoiceTotal, true);
const amounts = itemTotal > 0 ? {
  supplyAmount: itemSupplyTotal,
  taxAmount: itemTaxTotal,
  totalAmount: itemTotal,
} : {
  supplyAmount: fallbackInvoiceAmount.supply,
  taxAmount: fallbackInvoiceAmount.tax,
  totalAmount: fallbackInvoiceAmount.total,
};
if (amounts.supplyAmount <= 0 || amounts.taxAmount < 0 || amounts.totalAmount <= 0) return fail(400, 'AMOUNT_REQUIRED', '공급가액/세액/합계금액이 올바르지 않습니다.');

const supplier = {
  corpNum: digitsOnly(settings.bizno || body.supplier?.corpNum),
  corpName: coalesce(settings.company, body.supplier?.corpName),
  ceoName: coalesce(settings.ceo, body.supplier?.ceoName),
  addr: coalesce(settings.address, body.supplier?.addr),
  bizType: coalesce(settings.bizType, body.supplier?.bizType),
  bizClass: coalesce(settings.bizItem, body.supplier?.bizClass),
  contactId: coalesce(body.supplier?.contactId, $env.BAROBILL_CONTACT_ID),
  contactName: coalesce(body.supplier?.contactName, settings.ceo),
  tel: coalesce(settings.phone, body.supplier?.tel),
  hp: coalesce(body.supplier?.hp),
  email: coalesce(settings.email, body.supplier?.email),
};
const buyer = {
  corpNum: digitsOnly(invoice.customer_bizno || customer.business_no || customer.biz_no || body.buyer?.corpNum),
  corpName: coalesce(invoice.customer_name, customer.name, body.buyer?.corpName),
  ceoName: coalesce(invoice.customer_ceo_name, customer.ceo_name, body.buyer?.ceoName),
  addr: coalesce(invoice.customer_address, customer.business_address, customer.address1, body.buyer?.addr),
  bizType: coalesce(invoice.customer_biz_type, customer.business_type, customer.biz_type, body.buyer?.bizType),
  bizClass: coalesce(invoice.customer_biz_item, customer.business_item, customer.biz_item, body.buyer?.bizClass),
  contactName: coalesce(customer.name, invoice.customer_name, body.buyer?.contactName),
  tel: coalesce(customer.phone1, invoice.customer_phone, body.buyer?.tel),
  hp: coalesce(customer.mobile, body.buyer?.hp),
  email: coalesce(customer.email, body.buyer?.email),
};
const missing = [];
if (supplier.corpNum.length !== 10) missing.push('supplier.corpNum');
if (!supplier.contactId) missing.push('supplier.contactId');
if (!supplier.corpName) missing.push('supplier.corpName');
if (!supplier.ceoName) missing.push('supplier.ceoName');
if (buyer.corpNum.length !== 10) missing.push('buyer.corpNum');
if (!buyer.corpName) missing.push('buyer.corpName');
if (!buyer.ceoName) missing.push('buyer.ceoName');
if (!buyer.email || !buyer.email.includes('@')) missing.push('buyer.email');
if (missing.length) return fail(400, 'REQUIRED_FIELD_MISSING', '세금계산서 필수값이 누락되었습니다.', { missing });

const providerMgtKey = coalesce(body.providerMgtKey, taxInvoiceMeta.mgtKey, makeProviderMgtKey(invoiceId, invoiceNo, source.idempotencyKey));
const writeDate = normalizeDate(invoice.invoice_date || body.writeDate);
const serviceUrl = source.mode === 'production'
  ? String($env.BAROBILL_SERVICE_PROD_URL || 'https://ws.baroservice.com/TI.asmx').trim()
  : String($env.BAROBILL_SERVICE_TEST_URL || 'https://testws.baroservice.com/TI.asmx').trim();
const payloadHash = fnv1a(JSON.stringify({ invoiceId, invoiceNo, amounts, itemRows: itemRows.map(({ _amount, ...item }) => item), supplierCorpNum: supplier.corpNum, buyerCorpNum: buyer.corpNum }));
const crmPatchMeta = {
  ...meta,
  taxInvoiceStatus: 'requesting',
  taxInvoice: {
    ...taxInvoiceMeta,
    provider: 'barobill',
    issueType: 'normal',
    mgtKey: providerMgtKey,
    requestId: source.requestId,
    requestedAt: now,
    requestedBy: normalizeText(body.requestedBy) || 'crm',
    mailSent: body.sendEmail !== false,
    smsRequested: body.sendSms === true,
    statusCode: 'requesting',
    statusMessage: '바로빌 테스트 SOAP 발급 요청 준비됨',
  },
};
const logEntry = {
  request_id: source.requestId,
  idempotency_key: source.idempotencyKey,
  invoice_id: invoiceId,
  invoice_no: invoiceNo,
  provider: 'barobill',
  provider_mgt_key: providerMgtKey,
  mode: source.mode,
  supplier_corp_num: supplier.corpNum,
  request_payload_hash: payloadHash,
  status: 'requesting',
  created_at: existingLog?.created_at || now,
  updated_at: now,
  poll_attempt_count: existingLog?.poll_attempt_count || 0,
};
requestLog[source.idempotencyKey] = logEntry;
mgtLog[providerMgtKey] = source.idempotencyKey;

const issueSoapEnvelopeTemplate = buildIssueSoapTemplate({
  corpNum: supplier.corpNum,
  providerMgtKey,
  supplier,
  buyer,
  writeDate,
  amounts,
  itemRows,
  sendSms: body.sendSms === true,
  sendEmail: body.sendEmail !== false,
  mailTitle: body.mailTitle,
  purposeType: body.purposeType,
});
const mgtCheckSoapEnvelopeTemplate = buildMgtCheckSoapTemplate(supplier.corpNum, providerMgtKey);
return [{
  json: {
    success: true,
    ok: true,
    shouldCallProvider: true,
    httpStatus: 200,
    operation: 'issue',
    requestId: source.requestId,
    invoiceId,
    invoiceNo,
    idempotencyKey: source.idempotencyKey,
    provider: 'barobill',
    providerMgtKey,
    mode: source.mode,
    serviceUrl,
    supplierCorpNum: supplier.corpNum,
    amounts,
    sendEmail: body.sendEmail !== false,
    sendSms: body.sendSms === true,
    payloadHash,
    mgtCheckSoapEnvelopeTemplate,
    issueSoapEnvelopeTemplate,
    crmPatch: { memo: serializeMeta(invoice.memo, crmPatchMeta) },
  },
}];

